mapper.insert:
INSERT INTO teacher_course_assignment (
    teacher_id, course_id, status
) VALUES (
    #{teacherId}, #{courseId}, #{status}
)

mapper.select:
SELECT id, teacher_id, course_id, status, create_time, update_time
FROM teacher_course_assignment
WHERE teacher_id = #{teacherId}
  AND course_id = #{courseId}

mapper.update:
UPDATE teacher_course_assignment
SET status = 'ACTIVE'
WHERE id = #{id}

UPDATE teacher_course_assignment
SET status = 'CANCELLED'
WHERE teacher_id = #{teacherId}
  AND course_id = #{courseId}
  AND status = 'ACTIVE'
